import asyncio
import anthropic

async_client = anthropic.AsyncAnthropic()

async def classify_one(text: str, idx: int) -> dict:
    response = await async_client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=8,
        system="Classify sentiment: positive, negative, or neutral. One word only.",
        messages=[{"role": "user", "content": text}],
    )
    return {"idx": idx, "text": text[:40], "sentiment": response.content[0].text.strip().lower()}

async def classify_batch(texts: list[str], concurrency: int = 10) -> list[dict]:
    """Classify up to `concurrency` texts concurrently."""
    semaphore = asyncio.Semaphore(concurrency)

    async def bounded(text: str, idx: int) -> dict:
        async with semaphore:
            return await classify_one(text, idx)

    return await asyncio.gather(*[bounded(t, i) for i, t in enumerate(texts)])

reviews = [
    "Absolutely love this product!",
    "Arrived damaged and customer service was unhelpful.",
    "It does what it says. Nothing special.",
]
results = asyncio.run(classify_batch(reviews))
for r in results:
    print(r)
